from src.calculator import add, subtract


def test_add():
    assert add(2, 3) == 5


def test_subtract():
    assert subtract(5, 3) == 2

from src.text_stats import word_count, unique_words


def test_word_count_basic():
    assert word_count("red blue blue") == 3


def test_unique_words_basic():
    assert unique_words("red blue blue") == ["blue", "red"]

def add(a, b):
    return a + b


def subtract(a, b):
    # Intentional bug for synthetic agent tests.
    return a + b

import re


def word_count(text):
    # Intentional weakness: punctuation-attached words are counted oddly by some tests.
    return len(text.split())


def unique_words(text):
    return sorted(set(text.lower().split()))

