import importlib, traceback
mods=['tests.test_calculator','tests.test_text_stats']
for modname in mods:
    try:
        mod=importlib.import_module(modname)
    except Exception as e:
        print(f'ERROR importing {modname}: {e}')
        traceback.print_exc()
        continue
    for name in sorted(n for n in dir(mod) if n.startswith('test_')):
        fn=getattr(mod,name)
        if callable(fn):
            try:
                fn()
                print(f'PASSED {modname}.{name}')
            except Exception as e:
                print(f'FAILED {modname}.{name}: {type(e).__name__}: {e}')
                traceback.print_exc()
